{

	int id=T.size();

	T.push_back(node(l,r));

	T[id].ls=(l+1==r?-1:make(l,(l+r)/2));

	T[id].rs=(l+1==r?-1:make((l+r)/2,r));

	return id;

}



void update(int id,int l,int r,int t)

